//! Wasm entrypoints for topology masks, minimal compositing, and Lambert relight.
//! Hosts consume `Float32Array`-compatible buffers plus JSON provenance strings.

use wasm_bindgen::prelude::*;

use crate::imaging_composite::{composite_masked_rgb, mask_multiply_rgb, BlendMode};
use crate::imaging_relight::{relight_lambert_masked, LightDir};
use crate::topology_mask::{build_topology_alpha, RgbLayout, TopologyAlphaConfig};

/// Result of [`wasm_topology_mask_build_rgb_f32`]: soft alpha `[0,1]^wh` plus serde provenance JSON.
#[wasm_bindgen]
pub struct WasmTopologyMaskResult {
    #[wasm_bindgen(skip)]
    alpha: Vec<f32>,
    #[wasm_bindgen(skip)]
    provenance_json: String,
}

#[wasm_bindgen]
impl WasmTopologyMaskResult {
    #[wasm_bindgen(getter)]
    pub fn alpha(&self) -> Vec<f32> {
        self.alpha.clone()
    }

    #[wasm_bindgen(getter)]
    pub fn provenance_json(&self) -> String {
        self.provenance_json.clone()
    }
}

/// `rgb`: row-major unit linear floats `width * height * 3`.
#[wasm_bindgen(js_name = wasmTopologyMaskBuildRgbF32)]
pub fn wasm_topology_mask_build_rgb_f32(
    rgb: &[f32],
    width: u32,
    height: u32,
) -> Result<WasmTopologyMaskResult, JsError> {
    let config = TopologyAlphaConfig::default();
    let (alpha, prov) = build_topology_alpha(rgb, width, height, RgbLayout::SequentialRgb, &config)
        .map_err(|e| JsError::new(&e))?;
    let provenance_json =
        serde_json::to_string(&prov).map_err(|e| JsError::new(&format!("json: {}", e)))?;
    Ok(WasmTopologyMaskResult {
        alpha,
        provenance_json,
    })
}

/// Blend: `0` = SourceOver, `1` = Multiply (see [`BlendMode`]).
#[wasm_bindgen(js_name = wasmCompositeMaskedRgb)]
pub fn wasm_composite_masked_rgb(
    bg: &[f32],
    fg: &[f32],
    alpha: &[f32],
    width: u32,
    height: u32,
    blend_mode: u32,
) -> Result<Vec<f32>, JsError> {
    let blend = match blend_mode {
        0 => BlendMode::SourceOver,
        1 => BlendMode::Multiply,
        _ => return Err(JsError::new("blend_mode: 0 = SourceOver, 1 = Multiply")),
    };
    let w = width as usize;
    let h = height as usize;
    let pix = w * h;
    let need = pix * 3;
    let mut out = vec![0.0_f32; need];
    composite_masked_rgb(&mut out, bg, fg, alpha, width, height, blend)
        .map_err(|e| JsError::new(&e))?;
    Ok(out)
}

#[wasm_bindgen(js_name = wasmRelightLambertMasked)]
#[allow(clippy::too_many_arguments)]
pub fn wasm_relight_lambert_masked(
    rgb: &[f32],
    plane: &[f32],
    topology_alpha: &[f32],
    width: u32,
    height: u32,
    light_x: f32,
    light_y: f32,
    light_z: f32,
    diffuse_strength: f32,
    ambient: f32,
) -> Result<Vec<f32>, JsError> {
    let w = width as usize;
    let h = height as usize;
    let n = w * h;
    let mut out = vec![0.0_f32; n * 3];
    relight_lambert_masked(
        &mut out,
        rgb,
        plane,
        topology_alpha,
        w,
        h,
        LightDir(light_x, light_y, light_z),
        diffuse_strength,
        ambient,
    )
    .map_err(|e| JsError::new(&e))?;
    Ok(out)
}

/// Mask multiply: `dst = src * alpha` per RGB channel (`alpha` per pixel).
#[wasm_bindgen(js_name = wasmMaskMultiplyRgb)]
pub fn wasm_mask_multiply_rgb(
    src: &[f32],
    alpha: &[f32],
    width: u32,
    height: u32,
) -> Result<Vec<f32>, JsError> {
    let pix = width as usize * height as usize;
    let mut out = vec![0.0_f32; pix * 3];
    mask_multiply_rgb(&mut out, src, alpha, width, height).map_err(|e| JsError::new(&e))?;
    Ok(out)
}
